member.example:
Bind the VirtualizedList item source to a ViewModel collection using a serialized binder field — the target VirtualizedList is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private VirtualizedListItemSourceBinder _items;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public IReadOnlyList<IViewModel> _items;
    }


Bind the VirtualizedList item source by constructing the binder in code, with an optional filter and comparer.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private VirtualizedList _target;
        
        private VirtualizedListItemSourceBinder Items =>
            new(_target, filter: new MyFilter(), comparer: new MyComparer());
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public IReadOnlyList<IViewModel> _items;
    }

Bind the VirtualizedList item source to a ViewModel collection using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private VirtualizedListItemSourceMonoBinder _items;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public IReadOnlyList<IViewModel> _items;
    }
